		int centers = 50;
		int[] fanouts = { 1, 3, 1, 2, 1, 4, 1 };
		IRI[] predicates = predicates("urn:omni-accuracy:star:p", fanouts.length);
		StubSketchStatementSource store = new StubSketchStatementSource();
		for (int centerIndex = 0; centerIndex < centers; centerIndex++) {
			Resource center = iri("urn:omni-accuracy:star:center:" + centerIndex);
			for (int predicateIndex = 0; predicateIndex < predicates.length; predicateIndex++) {
				for (int leafIndex = 0; leafIndex < fanouts[predicateIndex]; leafIndex++) {
					store.add(st(center, predicates[predicateIndex],
							iri("urn:omni-accuracy:star:leaf:" + centerIndex + ':' + predicateIndex + ':'
									+ leafIndex)));
				}
			}
		}

		SketchBasedJoinEstimator estimator = track(new SketchBasedJoinEstimator(store, omniConfig()));
		estimator.rebuild();

